data["Terms"] = {
    "meta": {
        "title": "\u0634\u0631\u0648\u0637 \u0627\u0644\u062e\u062f\u0645\u0629",
        "description": "\u0634\u0631\u0648\u0637 \u062e\u062f\u0645\u0629 LumenLingo. \u062a\u0639\u0631\u0641 \u0639\u0644\u0649 \u062d\u0642\u0648\u0642\u0643 \u0648\u0645\u0633\u0624\u0648\u0644\u064a\u0627\u062a\u0643 \u0639\u0646\u062f \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u062a\u0637\u0628\u064a\u0642 \u062a\u0639\u0644\u0645 \u0627\u0644\u0644\u063a\u0627\u062a \u2014 \u0645\u0643\u062a\u0648\u0628\u0629 \u0628\u0644\u063a\u0629 \u0628\u0633\u064a\u0637\u0629.",
        "ogTitle": "\u0634\u0631\u0648\u0637 \u0627\u0644\u062e\u062f\u0645\u0629 \u2014 LumenLingo"
    },
    "breadcrumb": "\u0634\u0631\u0648\u0637 \u0627\u0644\u062e\u062f\u0645\u0629",
    "hero": {
        "heading": "\u0634\u0631\u0648\u0637 \u0627\u0644\u062e\u062f\u0645\u0629",
        "subtitle": "\u0642\u0648\u0627\u0639\u062f \u0627\u0633\u062a\u062e\u062f\u0627\u0645 LumenLingo \u2014 \u0645\u0643\u062a\u0648\u0628\u0629 \u0628\u0628\u0633\u0627\u0637\u0629 \u0644\u0623\u0646 \u0627\u0644\u0648\u062b\u0627\u0626\u0642 \u0627\u0644\u0642\u0627\u0646\u0648\u0646\u064a\u0629 \u0644\u0627 \u064a\u0646\u0628\u063a\u064a \u0623\u0646 \u062a\u062d\u062a\u0627\u062c \u0625\u0644\u0649 \u0642\u0627\u0645\u0648\u0633."
    },
    "introduction": {
        "heading": "\u0645\u0642\u062f\u0645\u0629",
        "p1": "\u0645\u0631\u062d\u0628\u0627\u064b \u0628\u0643 \u0641\u064a LumenLingo. \u062a\u062d\u0643\u0645 \u0634\u0631\u0648\u0637 \u0627\u0644\u062e\u062f\u0645\u0629 \u0647\u0630\u0647 (\u00ab\u0627\u0644\u0634\u0631\u0648\u0637\u00bb) \u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0643 \u0644\u062a\u0637\u0628\u064a\u0642 LumenLingo \u0644\u0644\u0647\u0627\u062a\u0641 \u0627\u0644\u0645\u062d\u0645\u0648\u0644 (\u00ab\u0627\u0644\u062a\u0637\u0628\u064a\u0642\u00bb) \u0627\u0644\u0630\u064a \u062a\u0634\u063a\u0644\u0647 LumenShore Ltd (\u00abLumenShore\u00bb \u0623\u0648 \u00ab\u0646\u062d\u0646\u00bb \u0623\u0648 \u00ab\u0644\u0646\u0627\u00bb).",
        "p2": "\u0628\u062a\u0646\u0632\u064a\u0644 \u0623\u0648 \u062a\u062b\u0628\u064a\u062a \u0623\u0648 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 LumenLingo\u060c \u0641\u0625\u0646\u0643 \u062a\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u0627\u0644\u0627\u0644\u062a\u0632\u0627\u0645 \u0628\u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637. \u0625\u0630\u0627 \u0644\u0645 \u062a\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u0623\u064a \u062c\u0632\u0621 \u0645\u0646 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637\u060c \u064a\u0631\u062c\u0649 \u0639\u062f\u0645 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u062a\u0637\u0628\u064a\u0642."
    },
    "acceptance": {
        "heading": "\u0642\u0628\u0648\u0644 \u0627\u0644\u0634\u0631\u0648\u0637",
        "intro": "\u0628\u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 LumenLingo \u0623\u0648 \u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0647\u060c \u0641\u0625\u0646\u0643 \u062a\u0624\u0643\u062f \u0623\u0646\u0643:",
        "li1": "\u062a\u0628\u0644\u063a \u0645\u0646 \u0627\u0644\u0639\u0645\u0631 13 \u0639\u0627\u0645\u0627\u064b \u0639\u0644\u0649 \u0627\u0644\u0623\u0642\u0644 (\u0623\u0648 \u0627\u0644\u062d\u062f \u0627\u0644\u0623\u062f\u0646\u0649 \u0644\u0644\u0633\u0646 \u0627\u0644\u0645\u0637\u0644\u0648\u0628 \u0641\u064a \u0646\u0637\u0627\u0642\u0643 \u0627\u0644\u0642\u0636\u0627\u0626\u064a).",
        "li2": "\u0625\u0630\u0627 \u0643\u0646\u062a \u062f\u0648\u0646 18 \u0639\u0627\u0645\u0627\u064b\u060c \u0641\u0642\u062f \u062d\u0635\u0644\u062a \u0639\u0644\u0649 \u0645\u0648\u0627\u0641\u0642\u0629 \u0648\u0644\u064a \u0627\u0644\u0623\u0645\u0631 \u0623\u0648 \u0627\u0644\u0648\u0635\u064a \u0627\u0644\u0642\u0627\u0646\u0648\u0646\u064a.",
        "li3": "\u0644\u062f\u064a\u0643 \u0627\u0644\u0623\u0647\u0644\u064a\u0629 \u0627\u0644\u0642\u0627\u0646\u0648\u0646\u064a\u0629 \u0644\u0625\u0628\u0631\u0627\u0645 \u0639\u0642\u062f \u0645\u0644\u0632\u0645.",
        "li4": "\u0633\u062a\u0644\u062a\u0632\u0645 \u0628\u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0648\u062c\u0645\u064a\u0639 \u0627\u0644\u0642\u0648\u0627\u0646\u064a\u0646 \u0627\u0644\u0645\u0639\u0645\u0648\u0644 \u0628\u0647\u0627."
    },
    "yourAccount": {
        "heading": "\u062d\u0633\u0627\u0628\u0643",
        "intro": "\u0644\u0627 \u064a\u062a\u0637\u0644\u0628 LumenLingo \u062a\u0633\u062c\u064a\u0644 \u062d\u0633\u0627\u0628 \u062a\u0642\u0644\u064a\u062f\u064a. \u0647\u0648\u064a\u062a\u0643 \u0641\u064a \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0645\u0631\u062a\u0628\u0637\u0629 \u0628\u0640 Apple ID \u0648\u062c\u0647\u0627\u0632\u0643. \u0623\u0646\u062a \u0645\u0633\u0624\u0648\u0644 \u0639\u0646:",
        "li1": "\u0627\u0644\u062d\u0641\u0627\u0638 \u0639\u0644\u0649 \u0623\u0645\u0627\u0646 Apple ID \u0648\u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u062c\u0647\u0627\u0632\u0643.",
        "li2": "\u062c\u0645\u064a\u0639 \u0627\u0644\u0623\u0646\u0634\u0637\u0629 \u0627\u0644\u0646\u0627\u062a\u062c\u0629 \u0639\u0646 \u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0643 \u0644\u0644\u062a\u0637\u0628\u064a\u0642.",
        "li3": "\u062a\u062d\u062f\u064a\u062b \u0646\u0638\u0627\u0645 \u062a\u0634\u063a\u064a\u0644 \u062c\u0647\u0627\u0632\u0643 \u0644\u0644\u062d\u0635\u0648\u0644 \u0639\u0644\u0649 \u0623\u0641\u0636\u0644 \u062a\u062c\u0631\u0628\u0629 \u0648\u0623\u0645\u0627\u0646."
    },
    "subscriptions": {
        "heading": "\u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643\u0627\u062a \u0648\u0627\u0644\u0641\u0648\u0627\u062a\u064a\u0631",
        "intro": "\u064a\u0642\u062f\u0645 LumenLingo \u0645\u0633\u062a\u0648\u064a\u0627\u062a \u0639\u0636\u0648\u064a\u0629 \u0645\u062c\u0627\u0646\u064a\u0629 \u0648\u0645\u0645\u064a\u0632\u0629. \u0627\u0644\u0645\u064a\u0632\u0627\u062a \u0627\u0644\u0645\u0645\u064a\u0632\u0629 \u062a\u062a\u0637\u0644\u0628 \u0627\u0634\u062a\u0631\u0627\u0643\u0627\u064b \u0645\u062f\u0641\u0648\u0639\u0627\u064b.",
        "li1": "<b>\u0627\u0644\u0641\u0648\u0627\u062a\u064a\u0631</b> \u2014 \u062c\u0645\u064a\u0639 \u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643\u0627\u062a \u062a\u062a\u0645 \u0645\u0639\u0627\u0644\u062c\u062a\u0647\u0627 \u0648\u0625\u062f\u0627\u0631\u062a\u0647\u0627 \u0628\u0648\u0627\u0633\u0637\u0629 Apple \u0639\u0628\u0631 App Store. \u0644\u0627 \u0646\u0639\u0627\u0644\u062c \u0627\u0644\u0645\u062f\u0641\u0648\u0639\u0627\u062a \u0645\u0628\u0627\u0634\u0631\u0629.",
        "li2": "<b>\u0627\u0644\u0645\u0633\u062a\u0648\u0649 \u0627\u0644\u0645\u062c\u0627\u0646\u064a</b> \u2014 \u064a\u0648\u0641\u0631 \u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u0645\u064a\u0632\u0627\u062a \u0627\u0644\u062a\u0639\u0644\u0645 \u0627\u0644\u0623\u0633\u0627\u0633\u064a\u0629 \u0645\u0639 \u0623\u0632\u0648\u0627\u062c \u0644\u063a\u0627\u062a \u0648\u0623\u0648\u0636\u0627\u0639 \u062a\u0645\u0627\u0631\u064a\u0646 \u0645\u062d\u062f\u0648\u062f\u0629.",
        "li3": "<b>\u0627\u0644\u0645\u0633\u062a\u0648\u064a\u0627\u062a \u0627\u0644\u0645\u0645\u064a\u0632\u0629</b> \u2014 \u062a\u0641\u062a\u062d \u0623\u0632\u0648\u0627\u062c \u0644\u063a\u0627\u062a \u0625\u0636\u0627\u0641\u064a\u0629 \u0648\u062a\u0645\u0627\u0631\u064a\u0646 \u063a\u064a\u0631 \u0645\u062d\u062f\u0648\u062f\u0629 \u0648\u0645\u0634\u0627\u0647\u062f \u0635\u0648\u062a\u064a\u0629 \u0648\u0643\u0631\u0627\u062a \u0627\u0644\u062a\u0646\u0641\u0633 \u0648\u0645\u064a\u0632\u0627\u062a \u0645\u0645\u064a\u0632\u0629 \u0623\u062e\u0631\u0649 \u0645\u0648\u0636\u062d\u0629 \u0641\u064a \u0627\u0644\u062a\u0637\u0628\u064a\u0642.",
        "li4": "<b>\u0627\u0644\u062a\u062c\u062f\u064a\u062f \u0627\u0644\u062a\u0644\u0642\u0627\u0626\u064a</b> \u2014 \u062a\u062a\u062c\u062f\u062f \u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643\u0627\u062a \u062a\u0644\u0642\u0627\u0626\u064a\u0627\u064b \u0645\u0627 \u0644\u0645 \u064a\u062a\u0645 \u0627\u0644\u0625\u0644\u063a\u0627\u0621 \u0642\u0628\u0644 24 \u0633\u0627\u0639\u0629 \u0639\u0644\u0649 \u0627\u0644\u0623\u0642\u0644 \u0645\u0646 \u0646\u0647\u0627\u064a\u0629 \u0641\u062a\u0631\u0629 \u0627\u0644\u0641\u0648\u062a\u0631\u0629 \u0627\u0644\u062d\u0627\u0644\u064a\u0629.",
        "li5": "<b>\u0627\u0644\u0625\u0644\u063a\u0627\u0621</b> \u2014 \u064a\u0645\u0643\u0646\u0643 \u0625\u0644\u063a\u0627\u0621 \u0627\u0634\u062a\u0631\u0627\u0643\u0643 \u0641\u064a \u0623\u064a \u0648\u0642\u062a \u0639\u0628\u0631 \u0625\u0639\u062f\u0627\u062f\u0627\u062a Apple ID \u2192 \u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643\u0627\u062a. \u064a\u0633\u0631\u064a \u0627\u0644\u0625\u0644\u063a\u0627\u0621 \u0641\u064a \u0646\u0647\u0627\u064a\u0629 \u0641\u062a\u0631\u0629 \u0627\u0644\u0641\u0648\u062a\u0631\u0629 \u0627\u0644\u062d\u0627\u0644\u064a\u0629.",
        "li6": "<b>\u0627\u0644\u0627\u0633\u062a\u0631\u062f\u0627\u062f</b> \u2014 \u0637\u0644\u0628\u0627\u062a \u0627\u0644\u0627\u0633\u062a\u0631\u062f\u0627\u062f \u062a\u062a\u0645 \u0645\u0639\u0627\u0644\u062c\u062a\u0647\u0627 \u0628\u0648\u0627\u0633\u0637\u0629 Apple \u0648\u0641\u0642\u064b\u0627 \u0644\u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u0627\u0633\u062a\u0631\u062f\u0627\u062f \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0647\u0645. \u062a\u0648\u0627\u0635\u0644 \u0645\u0639 \u062f\u0639\u0645 Apple \u0644\u0644\u0627\u0633\u062a\u0631\u062f\u0627\u062f.",
        "li7": "<b>\u062a\u063a\u064a\u064a\u0631\u0627\u062a \u0627\u0644\u0623\u0633\u0639\u0627\u0631</b> \u2014 \u0642\u062f \u0646\u0639\u062f\u0644 \u0623\u0633\u0639\u0627\u0631 \u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643. \u0633\u064a\u062a\u0645 \u0625\u062e\u0637\u0627\u0631\u0643 \u0645\u0633\u0628\u0642\u0627\u064b\u060c \u0648\u0633\u062a\u0633\u0631\u064a \u0627\u0644\u062a\u063a\u064a\u064a\u0631\u0627\u062a \u0641\u0642\u0637 \u0645\u0646 \u0641\u062a\u0631\u0629 \u0627\u0644\u062a\u062c\u062f\u064a\u062f \u0627\u0644\u062a\u0627\u0644\u064a\u0629."
    },
    "acceptableUse": {
        "heading": "\u0627\u0644\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u0645\u0642\u0628\u0648\u0644",
        "intro": "\u062a\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 LumenLingo \u0644\u0623\u063a\u0631\u0627\u0636 \u0642\u0627\u0646\u0648\u0646\u064a\u0629 \u0641\u0642\u0637 \u0648\u0648\u0641\u0642\u0627\u064b \u0644\u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637. \u0644\u0627 \u064a\u062c\u0648\u0632 \u0644\u0643:",
        "li1": "\u0625\u062c\u0631\u0627\u0621 \u0647\u0646\u062f\u0633\u0629 \u0639\u0643\u0633\u064a\u0629 \u0623\u0648 \u062a\u0641\u0643\u064a\u0643 \u0623\u0648 \u062a\u062d\u0644\u064a\u0644 \u0623\u064a \u062c\u0632\u0621 \u0645\u0646 \u0627\u0644\u062a\u0637\u0628\u064a\u0642.",
        "li2": "\u0645\u062d\u0627\u0648\u0644\u0629 \u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u0627\u0644\u0645\u0646\u0627\u0637\u0642 \u063a\u064a\u0631 \u0627\u0644\u0639\u0627\u0645\u0629 \u0641\u064a \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0623\u0648 \u0623\u0646\u0638\u0645\u062a\u0647 \u0623\u0648 \u0627\u0644\u062a\u0644\u0627\u0639\u0628 \u0628\u0647\u0627 \u0623\u0648 \u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0647\u0627.",
        "li3": "\u0646\u0633\u062e \u0623\u0648 \u062a\u0639\u062f\u064a\u0644 \u0623\u0648 \u062a\u0648\u0632\u064a\u0639 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0623\u0648 \u0625\u0646\u0634\u0627\u0621 \u0623\u0639\u0645\u0627\u0644 \u0645\u0634\u062a\u0642\u0629 \u0645\u0646\u0647.",
        "li4": "\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0628\u0637\u0631\u064a\u0642\u0629 \u0642\u062f \u062a\u0636\u0631 \u0623\u0648 \u062a\u0639\u0637\u0644 \u0623\u0648 \u062a\u0641\u0631\u0637 \u0641\u064a \u062a\u062d\u0645\u064a\u0644 \u0623\u0648 \u062a\u0639\u064a\u0642 \u0639\u0645\u0644\u0647.",
        "li5": "\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0633\u0643\u0631\u064a\u0628\u062a\u0627\u062a \u0622\u0644\u064a\u0629 \u0623\u0648 \u0628\u0648\u062a\u0627\u062a \u0623\u0648 \u0623\u062f\u0648\u0627\u062a \u0623\u062e\u0631\u0649 \u0644\u0644\u062a\u0641\u0627\u0639\u0644 \u0645\u0639 \u0627\u0644\u062a\u0637\u0628\u064a\u0642.",
        "li6": "\u0645\u062d\u0627\u0648\u0644\u0629 \u062a\u062c\u0627\u0648\u0632 \u0642\u064a\u0648\u062f \u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643 \u0623\u0648 \u0627\u0644\u0645\u0633\u062a\u0648\u0649."
    },
    "intellectualProperty": {
        "heading": "\u0627\u0644\u0645\u0644\u0643\u064a\u0629 \u0627\u0644\u0641\u0643\u0631\u064a\u0629",
        "p1": "\u062c\u0645\u064a\u0639 \u0627\u0644\u0645\u062d\u062a\u0648\u064a\u0627\u062a \u0641\u064a LumenLingo \u2014 \u0628\u0645\u0627 \u0641\u064a \u0630\u0644\u0643 \u0639\u0644\u0649 \u0633\u0628\u064a\u0644 \u0627\u0644\u0645\u062b\u0627\u0644 \u0644\u0627 \u0627\u0644\u062d\u0635\u0631 \u0645\u062d\u062a\u0648\u064a\u0627\u062a \u0627\u0644\u0628\u0637\u0627\u0642\u0627\u062a \u0627\u0644\u062a\u0639\u0644\u064a\u0645\u064a\u0629 \u0648\u0627\u0644\u062a\u0631\u062c\u0645\u0627\u062a \u0648\u0627\u0644\u0635\u0648\u062a \u0648\u0627\u0644\u0645\u0634\u0627\u0647\u062f \u0627\u0644\u0635\u0648\u062a\u064a\u0629 \u0648\u0627\u0644\u062a\u0635\u0645\u064a\u0645 \u0627\u0644\u0645\u0631\u0626\u064a \u0648\u062a\u0623\u062b\u064a\u0631\u0627\u062a \u0627\u0644\u0634\u064a\u062f\u0631 \u0648\u0627\u0644\u0631\u0633\u0648\u0645 \u0627\u0644\u0645\u062a\u062d\u0631\u0643\u0629 \u0648\u0627\u0633\u0645 LumenLingo \u0648\u0639\u0644\u0627\u0645\u0629 LumenShore \u0627\u0644\u062a\u062c\u0627\u0631\u064a\u0629 \u2014 \u0647\u064a \u0645\u0644\u0643\u064a\u0629 \u0641\u0643\u0631\u064a\u0629 \u0644\u0634\u0631\u0643\u0629 LumenShore Ltd \u0648\u0645\u062d\u0645\u064a\u0629 \u0628\u0642\u0648\u0627\u0646\u064a\u0646 \u062d\u0642\u0648\u0642 \u0627\u0644\u0646\u0634\u0631 \u0648\u0627\u0644\u0639\u0644\u0627\u0645\u0627\u062a \u0627\u0644\u062a\u062c\u0627\u0631\u064a\u0629 \u0648\u063a\u064a\u0631\u0647\u0627 \u0645\u0646 \u0642\u0648\u0627\u0646\u064a\u0646 \u0627\u0644\u0645\u0644\u0643\u064a\u0629 \u0627\u0644\u0641\u0643\u0631\u064a\u0629.",
        "p2": "\u064a\u0645\u0646\u062d\u0643 \u0627\u0634\u062a\u0631\u0627\u0643\u0643 \u062a\u0631\u062e\u064a\u0635\u0627\u064b \u0645\u062d\u062f\u0648\u062f\u0627\u064b \u0648\u063a\u064a\u0631 \u062d\u0635\u0631\u064a \u0648\u063a\u064a\u0631 \u0642\u0627\u0628\u0644 \u0644\u0644\u062a\u062d\u0648\u064a\u0644 \u0648\u0642\u0627\u0628\u0644 \u0644\u0644\u0625\u0644\u063a\u0627\u0621 \u0644\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0644\u0623\u063a\u0631\u0627\u0636 \u062a\u0639\u0644\u0645 \u0627\u0644\u0644\u063a\u0627\u062a \u0627\u0644\u0634\u062e\u0635\u064a\u0629 \u0648\u063a\u064a\u0631 \u0627\u0644\u062a\u062c\u0627\u0631\u064a\u0629. \u0644\u0627 \u064a\u0634\u0645\u0644 \u0647\u0630\u0627 \u0627\u0644\u062a\u0631\u062e\u064a\u0635 \u0627\u0644\u062d\u0642 \u0641\u064a:",
        "li1": "\u0627\u0633\u062a\u0646\u0633\u0627\u062e \u0623\u0648 \u062a\u0648\u0632\u064a\u0639 \u0623\u0648 \u0639\u0631\u0636 \u0623\u064a \u0645\u062d\u062a\u0648\u0649 \u0645\u0646 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0639\u0644\u0646\u064a\u0627\u064b.",
        "li2": "\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0623\u064a \u0645\u062d\u062a\u0648\u0649 \u0644\u0623\u063a\u0631\u0627\u0636 \u062a\u062c\u0627\u0631\u064a\u0629 \u0623\u0648 \u0641\u064a \u0645\u0646\u062a\u062c\u0627\u062a \u0645\u0646\u0627\u0641\u0633\u0629.",
        "li3": "\u0625\u0632\u0627\u0644\u0629 \u0623\u0648 \u062a\u0639\u062f\u064a\u0644 \u0623\u064a \u0625\u0634\u0639\u0627\u0631\u0627\u062a \u0623\u0648 \u0639\u0644\u0627\u0645\u0627\u062a \u0645\u0644\u0643\u064a\u0629."
    },
    "userContent": {
        "heading": "\u0645\u062d\u062a\u0648\u0649 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645 \u0648\u0628\u064a\u0627\u0646\u0627\u062a\u0647",
        "p1": "\u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u062a\u0639\u0644\u0645 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643 (\u0627\u0644\u062a\u0642\u062f\u0645\u060c \u0627\u0644\u062a\u0641\u0636\u064a\u0644\u0627\u062a\u060c \u0633\u062c\u0644 \u0627\u0644\u062a\u0645\u0627\u0631\u064a\u0646) \u0645\u062e\u0632\u0646\u0629 \u0639\u0644\u0649 \u062c\u0647\u0627\u0632\u0643 \u0648\u062d\u0633\u0627\u0628 iCloud \u0627\u0644\u0634\u062e\u0635\u064a. \u0644\u0627 \u062a\u062f\u0639\u064a LumenShore \u0645\u0644\u0643\u064a\u0629 \u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u062a\u0639\u0644\u0645 \u0627\u0644\u0634\u062e\u0635\u064a\u0629 \u0627\u0644\u062e\u0627\u0635\u0629 \u0628\u0643.",
        "p2": "\u0644\u0645\u0632\u064a\u062f \u0645\u0646 \u0627\u0644\u062a\u0641\u0627\u0635\u064a\u0644 \u062d\u0648\u0644 \u0643\u064a\u0641\u064a\u0629 \u062a\u0639\u0627\u0645\u0644\u0646\u0627 \u0645\u0639 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a\u060c \u064a\u0631\u062c\u0649 \u0627\u0644\u0627\u0637\u0644\u0627\u0639 \u0639\u0644\u0649 <privacyLink>\u0633\u064a\u0627\u0633\u0629 \u0627\u0644\u062e\u0635\u0648\u0635\u064a\u0629</privacyLink>."
    },
    "disclaimers": {
        "heading": "\u0625\u062e\u0644\u0627\u0621 \u0627\u0644\u0645\u0633\u0624\u0648\u0644\u064a\u0629",
        "intro": "\u064a\u062a\u0645 \u062a\u0642\u062f\u064a\u0645 LumenLingo \u00ab\u0643\u0645\u0627 \u0647\u0648\u00bb \u0648\u00ab\u062d\u0633\u0628 \u0627\u0644\u062a\u0648\u0641\u0631\u00bb. \u0631\u063a\u0645 \u0633\u0639\u064a\u0646\u0627 \u0644\u0644\u062f\u0642\u0629 \u0648\u0627\u0644\u062c\u0648\u062f\u0629\u060c \u0644\u0627 \u0646\u0642\u062f\u0645 \u0623\u064a \u0636\u0645\u0627\u0646\u0627\u062a \u0635\u0631\u064a\u062d\u0629 \u0623\u0648 \u0636\u0645\u0646\u064a\u0629 \u0628\u0634\u0623\u0646:",
        "li1": "\u062f\u0642\u0629 \u0623\u0648 \u0627\u0643\u062a\u0645\u0627\u0644 \u0623\u064a \u0645\u062d\u062a\u0648\u0649 \u0644\u063a\u0648\u064a \u0623\u0648 \u062a\u0631\u062c\u0645\u0627\u062a.",
        "li2": "\u0639\u0645\u0644 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0628\u062f\u0648\u0646 \u0627\u0646\u0642\u0637\u0627\u0639 \u0623\u0648 \u0623\u062e\u0637\u0627\u0621.",
        "li3": "\u0627\u0644\u0646\u062a\u0627\u0626\u062c \u0627\u0644\u062a\u064a \u0642\u062f \u062a\u062d\u0642\u0642\u0647\u0627 \u0628\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u062a\u0637\u0628\u064a\u0642.",
        "li4": "\u062a\u0648\u0641\u0631 \u0645\u064a\u0632\u0627\u062a \u0645\u0639\u064a\u0646\u0629 \u0641\u064a \u0623\u064a \u0648\u0642\u062a.",
        "supplement": "LumenLingo \u0647\u0648 \u0623\u062f\u0627\u0629 \u062a\u0639\u0644\u0645 \u062a\u0643\u0645\u064a\u0644\u064a\u0629. \u0644\u0627 \u064a\u062d\u0644 \u0645\u062d\u0644 \u062a\u0639\u0644\u064a\u0645 \u0627\u0644\u0644\u063a\u0627\u062a \u0627\u0644\u0645\u0647\u0646\u064a \u0623\u0648 \u062e\u062f\u0645\u0627\u062a \u0627\u0644\u062a\u0631\u062c\u0645\u0629 \u0627\u0644\u0645\u0639\u062a\u0645\u062f\u0629 \u0623\u0648 \u0627\u0644\u062f\u0648\u0631\u0627\u062a \u0627\u0644\u0623\u0643\u0627\u062f\u064a\u0645\u064a\u0629."
    },
    "limitationOfLiability": {
        "heading": "\u062a\u062d\u062f\u064a\u062f \u0627\u0644\u0645\u0633\u0624\u0648\u0644\u064a\u0629",
        "intro": "\u0625\u0644\u0649 \u0623\u0642\u0635\u0649 \u062d\u062f \u064a\u0633\u0645\u062d \u0628\u0647 \u0627\u0644\u0642\u0627\u0646\u0648\u0646 \u0627\u0644\u0645\u0639\u0645\u0648\u0644 \u0628\u0647\u060c \u0644\u0627 \u062a\u062a\u062d\u0645\u0644 LumenShore Ltd \u0627\u0644\u0645\u0633\u0624\u0648\u0644\u064a\u0629 \u0639\u0646 \u0627\u0644\u0623\u0636\u0631\u0627\u0631 \u063a\u064a\u0631 \u0627\u0644\u0645\u0628\u0627\u0634\u0631\u0629 \u0623\u0648 \u0627\u0644\u0639\u0631\u0636\u064a\u0629 \u0623\u0648 \u0627\u0644\u062e\u0627\u0635\u0629 \u0623\u0648 \u0627\u0644\u062a\u0628\u0639\u064a\u0629 \u0623\u0648 \u0627\u0644\u0639\u0642\u0627\u0628\u064a\u0629\u060c \u0623\u0648 \u062e\u0633\u0627\u0631\u0629 \u0627\u0644\u0623\u0631\u0628\u0627\u062d \u0623\u0648 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0623\u0648 \u0627\u0644\u0633\u0645\u0639\u0629 \u0627\u0644\u0646\u0627\u062a\u062c\u0629 \u0639\u0646:",
        "li1": "\u0627\u0633\u062a\u062e\u062f\u0627\u0645 (\u0623\u0648 \u0639\u062f\u0645 \u0627\u0644\u0642\u062f\u0631\u0629 \u0639\u0644\u0649 \u0627\u0633\u062a\u062e\u062f\u0627\u0645) \u0627\u0644\u062a\u0637\u0628\u064a\u0642.",
        "li2": "\u0623\u064a \u0623\u062e\u0637\u0627\u0621 \u0623\u0648 \u0625\u063a\u0641\u0627\u0644\u0627\u062a \u0623\u0648 \u0639\u062f\u0645 \u062f\u0642\u0629 \u0641\u064a \u0627\u0644\u0645\u062d\u062a\u0648\u0649.",
        "li3": "\u0627\u0644\u0648\u0635\u0648\u0644 \u063a\u064a\u0631 \u0627\u0644\u0645\u0635\u0631\u062d \u0628\u0647 \u0625\u0644\u0649 \u062c\u0647\u0627\u0632\u0643 \u0623\u0648 \u0628\u064a\u0627\u0646\u0627\u062a\u0643 (\u063a\u064a\u0631 \u0627\u0644\u0646\u0627\u062a\u062c \u0639\u0646 \u0625\u0647\u0645\u0627\u0644\u0646\u0627).",
        "li4": "\u0623\u064a \u0627\u0646\u0642\u0637\u0627\u0639 \u0623\u0648 \u062a\u0648\u0642\u0641 \u0641\u064a \u0627\u0644\u062e\u062f\u0645\u0629.",
        "cap": "\u0625\u062c\u0645\u0627\u0644\u064a \u0645\u0633\u0624\u0648\u0644\u064a\u062a\u0646\u0627 \u0639\u0646 \u0623\u064a \u0645\u0637\u0627\u0644\u0628\u0629 \u0646\u0627\u062a\u062c\u0629 \u0639\u0646 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0623\u0648 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 LumenLingo \u0644\u0646 \u062a\u062a\u062c\u0627\u0648\u0632 \u0627\u0644\u0645\u0628\u0644\u063a \u0627\u0644\u0630\u064a \u062f\u0641\u0639\u062a\u0647 \u0644\u0644\u062a\u0637\u0628\u064a\u0642 \u062e\u0644\u0627\u0644 12 \u0634\u0647\u0631\u0627\u064b \u0642\u0628\u0644 \u0627\u0644\u0645\u0637\u0627\u0644\u0628\u0629."
    },
    "termination": {
        "heading": "\u0627\u0644\u0625\u0646\u0647\u0627\u0621",
        "p1": "\u064a\u0645\u0643\u0646\u0643 \u0627\u0644\u062a\u0648\u0642\u0641 \u0639\u0646 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 LumenLingo \u0641\u064a \u0623\u064a \u0648\u0642\u062a \u0628\u062d\u0630\u0641 \u0627\u0644\u062a\u0637\u0628\u064a\u0642. \u0625\u0630\u0627 \u0643\u0627\u0646 \u0644\u062f\u064a\u0643 \u0627\u0634\u062a\u0631\u0627\u0643 \u0646\u0634\u0637\u060c \u064a\u062c\u0628 \u0625\u0644\u063a\u0627\u0624\u0647 \u0628\u0634\u0643\u0644 \u0645\u0646\u0641\u0635\u0644 \u0639\u0628\u0631 \u0625\u062f\u0627\u0631\u0629 \u0627\u0634\u062a\u0631\u0627\u0643\u0627\u062a Apple.",
        "p2": "\u0646\u062d\u062a\u0641\u0638 \u0628\u0627\u0644\u062d\u0642 \u0641\u064a \u062a\u0639\u0644\u064a\u0642 \u0623\u0648 \u0625\u0646\u0647\u0627\u0621 \u0648\u0635\u0648\u0644\u0643 \u0625\u0644\u0649 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0625\u0630\u0627 \u0627\u0639\u062a\u0642\u062f\u0646\u0627 \u0628\u0634\u0643\u0644 \u0645\u0639\u0642\u0648\u0644 \u0623\u0646\u0643 \u0627\u0646\u062a\u0647\u0643\u062a \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637. \u0639\u0646\u062f \u0627\u0644\u0625\u0646\u0647\u0627\u0621:",
        "li1": "\u064a\u062a\u0645 \u0625\u0644\u063a\u0627\u0621 \u062a\u0631\u062e\u064a\u0635\u0643 \u0644\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0641\u0648\u0631\u0627\u064b.",
        "li2": "\u062a\u0628\u0642\u0649 \u0628\u064a\u0627\u0646\u0627\u062a\u0643 \u0627\u0644\u0645\u062d\u0644\u064a\u0629 \u0639\u0644\u0649 \u062c\u0647\u0627\u0632\u0643 \u062d\u062a\u0649 \u062a\u062d\u0630\u0641\u0647\u0627.",
        "li3": "\u064a\u062c\u0628 \u0625\u0644\u063a\u0627\u0621 \u0627\u0644\u0627\u0634\u062a\u0631\u0627\u0643\u0627\u062a \u0627\u0644\u0646\u0634\u0637\u0629 \u0639\u0628\u0631 Apple.",
        "li4": "\u0627\u0644\u0628\u0646\u0648\u062f \u0627\u0644\u062a\u064a \u0628\u0637\u0628\u064a\u0639\u062a\u0647\u0627 \u064a\u062c\u0628 \u0623\u0646 \u062a\u0628\u0642\u0649 \u0633\u0627\u0631\u064a\u0629 \u0628\u0639\u062f \u0627\u0644\u0625\u0646\u0647\u0627\u0621 \u062a\u0638\u0644 \u0633\u0627\u0631\u064a\u0629."
    },
    "governingLaw": {
        "heading": "\u0627\u0644\u0642\u0627\u0646\u0648\u0646 \u0627\u0644\u0645\u0639\u0645\u0648\u0644 \u0628\u0647",
        "p1": "\u062a\u062e\u0636\u0639 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0644\u0642\u0648\u0627\u0646\u064a\u0646 \u0625\u0646\u062c\u0644\u062a\u0631\u0627 \u0648\u0648\u064a\u0644\u0632 \u0648\u062a\u0641\u0633\u0631 \u0648\u0641\u0642\u0627\u064b \u0644\u0647\u0627\u060c \u062f\u0648\u0646 \u0627\u0644\u0646\u0638\u0631 \u0625\u0644\u0649 \u0645\u0628\u0627\u062f\u0626 \u062a\u0646\u0627\u0632\u0639 \u0627\u0644\u0642\u0648\u0627\u0646\u064a\u0646.",
        "p2": "\u0623\u064a \u0646\u0632\u0627\u0639\u0627\u062a \u0646\u0627\u062a\u062c\u0629 \u0639\u0646 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u062a\u062e\u0636\u0639 \u0644\u0644\u0627\u062e\u062a\u0635\u0627\u0635 \u0627\u0644\u062d\u0635\u0631\u064a \u0644\u0645\u062d\u0627\u0643\u0645 \u0625\u0646\u062c\u0644\u062a\u0631\u0627 \u0648\u0648\u064a\u0644\u0632. \u0648\u0645\u0639 \u0630\u0644\u0643\u060c \u0644\u0627 \u064a\u0624\u062b\u0631 \u0630\u0644\u0643 \u0639\u0644\u0649 \u062d\u0642\u0648\u0642\u0643 \u0627\u0644\u0642\u0627\u0646\u0648\u0646\u064a\u0629 \u0643\u0645\u0633\u062a\u0647\u0644\u0643 \u0641\u064a \u0628\u0644\u062f \u0625\u0642\u0627\u0645\u062a\u0643."
    },
    "changes": {
        "heading": "\u062a\u063a\u064a\u064a\u0631\u0627\u062a \u0627\u0644\u0634\u0631\u0648\u0637",
        "p1": "\u0642\u062f \u0646\u0642\u0648\u0645 \u0628\u062a\u062d\u062f\u064a\u062b \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0645\u0646 \u0648\u0642\u062a \u0644\u0622\u062e\u0631. \u0639\u0646\u062f \u0625\u062c\u0631\u0627\u0621 \u062a\u063a\u064a\u064a\u0631\u0627\u062a \u062c\u0648\u0647\u0631\u064a\u0629\u060c \u0633\u0646\u0642\u0648\u0645 \u0628\u062a\u062d\u062f\u064a\u062b \u062a\u0627\u0631\u064a\u062e \u00ab\u0622\u062e\u0631 \u062a\u062d\u062f\u064a\u062b\u00bb \u0641\u064a \u0623\u0639\u0644\u0649 \u0627\u0644\u0635\u0641\u062d\u0629 \u0648\u0642\u062f \u0646\u062e\u0637\u0631\u0643 \u0639\u0628\u0631 \u0627\u0644\u062a\u0637\u0628\u064a\u0642.",
        "p2": "\u0627\u0633\u062a\u0645\u0631\u0627\u0631\u0643 \u0641\u064a \u0627\u0633\u062a\u062e\u062f\u0627\u0645 LumenLingo \u0628\u0639\u062f \u0646\u0634\u0631 \u0627\u0644\u062a\u063a\u064a\u064a\u0631\u0627\u062a \u064a\u0639\u0646\u064a \u0642\u0628\u0648\u0644\u0643 \u0644\u0644\u0634\u0631\u0648\u0637 \u0627\u0644\u0645\u0639\u062f\u0644\u0629. \u0625\u0630\u0627 \u0644\u0645 \u062a\u0648\u0627\u0641\u0642\u060c \u062a\u0648\u0642\u0641 \u0639\u0646 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0648\u0623\u0644\u063a\u0650 \u0623\u064a \u0627\u0634\u062a\u0631\u0627\u0643\u0627\u062a \u0646\u0634\u0637\u0629."
    },
    "contactUs": {
        "heading": "\u0627\u062a\u0635\u0644 \u0628\u0646\u0627",
        "intro": "\u0625\u0630\u0627 \u0643\u0627\u0646\u062a \u0644\u062f\u064a\u0643 \u0623\u0633\u0626\u0644\u0629 \u062d\u0648\u0644 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0623\u0648 \u062a\u062d\u062a\u0627\u062c \u0625\u0644\u0649 \u0627\u0644\u0625\u0628\u0644\u0627\u063a \u0639\u0646 \u0645\u0634\u0643\u0644\u0629\u060c \u062a\u0648\u0627\u0635\u0644 \u0645\u0639\u0646\u0627:",
        "email": "<b>\u0627\u0644\u0628\u0631\u064a\u062f \u0627\u0644\u0625\u0644\u0643\u062a\u0631\u0648\u0646\u064a</b>: <emailLink>support@lumenlingo.com</emailLink>",
        "company": "<b>\u0627\u0644\u0634\u0631\u0643\u0629</b>: LumenShore Ltd\u060c \u0627\u0644\u0645\u0645\u0644\u0643\u0629 \u0627\u0644\u0645\u062a\u062d\u062f\u0629",
        "responseTime": "\u0639\u0627\u062f\u0629\u064b \u0645\u0627 \u0646\u0631\u062f \u062e\u0644\u0627\u0644 48 \u0633\u0627\u0639\u0629."
    }
}

